#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e4+5,MOD=1e4;
vector<PII> g[MAXN];
int x[MAXN],c[MAXN],d[MAXN][2],lt[MAXN],q[10000005];
int ql=0,l=0,n,m,s,t,f;
signed main(void)
{
    //freopen("in.txt","r",stdin);
    //freopen("out.txt","w",stdout);
    n=read(),m=read(),s=read(),t=read(),f=read();
    FOR(i,1,m)
    {
        int x=read(),y=read(),z=read();
        g[x].pb(mk(y,z));
        d[x][1]++;
        d[y][0]++;
    }
    q[l++]=s;
    wh(ql<l)
    {
        int u=q[ql++];
        lt[u]=1;
        FOI(e,g[u])
        {
            if(lt[e.fst]==0)
            {
                q[l++]=e.fst;
            }
        }
    }
    FOR(i,1,n)
    {
        if(lt[i]==0)
        {
            FOI(e,g[i])
            {
                d[e.fst][0]--;
            }
            g[i].clear();
        }
    }
    ql=0;
    l=0;
    q[l++]=s;
    c[s]=1;
    wh(ql<l)//topsort
    {
        int u=q[ql++];
        FOI(e,g[u])
        {
            int v=e.fst,w=e.snd;
            c[v]=(c[v]+c[u])%MOD;
            x[v]=(x[v]+x[u]+(w*c[u]%MOD))%MOD;
            d[v][0]--;
            if(d[v][0]==0)
            {
                q[l++]=v;
            }
        }
    }
    writeln((x[t]+(f*((c[t]-1+MOD)%MOD)%MOD))%MOD);
    return false;
}
